let html5Tags=["section","article","main","aside","header","footer","nav","figure","figcaption","address","canvas","details","summary","audio","video","source","datalist","meter","progress","output","time","mark"];for(let e=0;e<html5Tags.length;e++)document.createElement(html5Tags[e]);const menuHamburger=document.querySelector(".header__hamburger"),menu=document.querySelector(".header__nav-content"),toggleMenu=()=>{menu.classList.toggle("_active"),menuHamburger.classList.toggle("_active")};menuHamburger.addEventListener("click",e=>{e.stopPropagation(),toggleMenu()}),document.addEventListener("click",e=>{let o=e.target,t=o==menu||menu.contains(o),r=o==menuHamburger,l=menu.classList.contains("_active");t||r||!l||toggleMenu()}),window.onscroll=()=>{let e=document.querySelector(".header"),o=document.querySelector(".header__logo-link"),t=document.querySelectorAll(".header__nav-link"),r=document.documentElement.scrollTop||document.body.scrollTop;if(r>50){e.classList.add("_onscroll"),o.classList.add("_onscroll");for(const e of t)e.classList.add("_onscroll")}else if(r<50){e.classList.remove("_onscroll"),o.classList.remove("_onscroll");for(const e of t)e.classList.remove("_onscroll")}};const footerArrow=document.querySelector(".footer__arrow"),footerColumn=document.querySelector(".footer__column");footerArrow.addEventListener("click",()=>{footerArrow.classList.toggle("_active"),footerColumn.classList.toggle("_active")});